import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"论小洛伦佐去世后佛罗伦","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/210-论小洛伦佐去世后佛罗伦.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/210-论小洛伦佐去世后佛罗伦.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/210-论小洛伦佐去世后佛罗伦.md"};function o(s,a,n,_,m,d){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"论小洛伦佐去世后佛罗伦",tabindex:"-1"},[t("论小洛伦佐去世后佛罗伦 "),e("a",{class:"header-anchor",href:"#论小洛伦佐去世后佛罗伦","aria-label":'Permalink to "论小洛伦佐去世后佛罗伦"'},"​")],-1),e("p",null,"论小洛伦佐去世后佛罗伦萨的政务 君主统治绅士，国王统治君主。不过，既然在一个共和国可以运转自如的 地方建立君主国实属不易，由于困难因而对于任何希望被视为仁慈和善良 的人来说都是残酷的、不足取的；那么,我还是不去进一步探讨君主国， 转而谈谈共和国。这既是因为佛罗伦萨非常适合采用这种政府形式，也是 因为我知道陛下正有此意。我相信，您对建立共和国犹豫不决，是因为您 希望找到这样一种安排，使得您的权势在佛罗伦萨可以继续显赫，您的朋 友可以安居乐业。我确信，我已经发现了这样一种安排，并恳求陛下对我 的发现给予关注；这样，如果它有什么益处，您可以充分利用，而且您也 可以了解我竭诚为您效劳的忠心。您会发现，在我的这个共和国中，您的 权势不但得到维护，而且有增无减，您的朋友继续享有荣誉和安全，普通 公民也有充分的理由感到满意。怀着最崇高的敬意，我恳求陛下在没有通 读完我的进言献策之前，不要非难或赞赏它。同样，我也恳求您不要对关 于行政长官的某些改革(建议)感到惊愕。因为，在事情没有组织好的地 方，旧事物保留得越少，腐败的事物也就越少。 那些创建共和国的人应该为存在于所有城邦中的三类不同的人—上 层人物、中间阶层以及底层民众——安排好恰如其分的位置。虽然前面已 经提及，在佛罗伦萨，公民享有平等；然而，依旧有些公民雄心勃勃，认 为自己理应高人一等。在组建共和国时，必须满足这些人。事实上，上一 届政府之所以倒台，恰恰就是因为没有满足这样一些人。对于这些人而 言，除非赋予共和国的最高职位以威严，而这种威严又掌控在他们手中， 否则就不能让他们心满意足。 如果执政团以及顾问团的成员保持和过去一样的情形，那么,就不 可能把这种威严赋予佛罗伦萨政府的最高职位。按照这些成员的遴选方 式——重要而有影响的人物现在很少占据其中——政府的威严要么被授 予下层(这是有悖于任何一种政治秩序的),要么被放弃而置于私人手 中。①因此，必须纠正这一方式，并且通过纠正来满足城邦中最高阶层的 ①也就是说，允许政府掌控在政治老板( political bosses) 而不是在职官员手中，就像科西莫时代 一 样。——英译 者 注",-1),e("p",null,"马基雅维利全集 Opere complete di Niccolo Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
